import{_ as e,o as t,c as s,ae as o}from"./chunks/framework.B6gjLfeO.js";const r="/casaos_final.png",n="/linkease_final.png",u=JSON.parse('{"title":"🚀 小白必看：如何用手机随时随地访问家里的硬盘？（易有云篇）","description":"","frontmatter":{},"headers":[],"relativePath":"tutorials/nas-phone-access.md","filePath":"tutorials/nas-phone-access.md"}'),i={name:"tutorials/nas-phone-access.md"};function l(p,a,c,_,h,d){return t(),s("div",null,[...a[0]||(a[0]=[o('<h1 id="🚀-小白必看-如何用手机随时随地访问家里的硬盘-易有云篇" tabindex="-1">🚀 小白必看：如何用手机随时随地访问家里的硬盘？（易有云篇） <a class="header-anchor" href="#🚀-小白必看-如何用手机随时随地访问家里的硬盘-易有云篇" aria-label="Permalink to &quot;🚀 小白必看：如何用手机随时随地访问家里的硬盘？（易有云篇）&quot;">​</a></h1><p>很多朋友搭建好 CasaOS 之后，都想知道怎么在手机上也能看到硬盘里的照片和文件。今天教大家一个超级简单的方法！</p><h2 id="📌-第一步-进入易有云后台" tabindex="-1">📌 第一步：进入易有云后台 <a class="header-anchor" href="#📌-第一步-进入易有云后台" aria-label="Permalink to &quot;📌 第一步：进入易有云后台&quot;">​</a></h2><p>打开你的 CasaOS 主界面，往下滑一点找到「<strong>旧应用程序（待重建）</strong>」区域，看到那个<strong>带有蓝色云朵的 linkease（易有云）</strong> 图标了吗？（如下图所示），点击它进入易有云后台！</p><p><img src="'+r+'" alt="第一步：进入易有云后台"></p><h2 id="📌-第二步-下载手机-app-并绑定设备" tabindex="-1">📌 第二步：下载手机 App 并绑定设备 <a class="header-anchor" href="#📌-第二步-下载手机-app-并绑定设备" aria-label="Permalink to &quot;📌 第二步：下载手机 App 并绑定设备&quot;">​</a></h2><ol><li>进入易有云网页后台后，看屏幕的最<strong>右上角</strong>！</li><li>看到红框圈出来的那个<strong>像手机一样的小图标</strong>了吗？（如下图所示），点它！</li><li>这时屏幕上会弹出一个二维码。拿出你的手机扫码，就能下载易有云的官方 App。</li><li>安装好 App 后，根据提示扫码完成设备绑定。</li></ol><p><img src="'+n+'" alt="第二步：下载手机 App 并绑定设备"></p><h2 id="✅-大功告成" tabindex="-1">✅ 大功告成！ <a class="header-anchor" href="#✅-大功告成" aria-label="Permalink to &quot;✅ 大功告成！&quot;">​</a></h2><p>现在打开手机上的易有云 App，你的 NAS 硬盘（Storage1）里的所有照片、视频和文件，随时随地都能访问啦！赶紧去试试吧！</p>',10)])])}const f=e(i,[["render",l]]);export{u as __pageData,f as default};
